export const meta = {
  name: 'qa-restful-db-insert',
  description: 'QA workflow: RESTful web service form data to DB registration pattern',
  phases: [
    { title: 'SemanticSearch', detail: 'Search knowledge files for relevant sections' },
    { title: 'ReadSections', detail: 'Read selected section content' },
    { title: 'GenerateAnswer', detail: 'Generate and verify Japanese answer' }
  ]
}

// Step 3: Semantic search
phase('SemanticSearch')
const searchQuery = 'フォームから受け取ったデータをDBに登録する処理の実装パターンを知りたい（処理方式: RESTfulウェブサービス）（目的: 実装したい）'

const searchResult = await agent(
  `You are executing a semantic search over Nablarch knowledge files.

Working directory: /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6

Execute the semantic search workflow at workflows/semantic-search.md with the following query:
"${searchQuery}"

Follow the workflow exactly as written in semantic-search.md.

Return the result as JSON with this structure:
{
  "selected_sections": [
    {"file": "<full path to json file>", "section_id": "<sN>", "relevance": "<high|partial>", "reason": "<why selected>"}
  ],
  "selected_pages": [
    {"path": "<page path relative to knowledge/>", "reason": "<why selected>"}
  ],
  "excluded_pages": [
    {"path": "<page path relative to knowledge/>", "reason": "<why excluded>"}
  ],
  "excluded_sections": [
    {"file": "<full path>", "section_id": "<sN>", "reason": "<why excluded>"}
  ]
}`,
  { label: 'semantic-search', phase: 'SemanticSearch', schema: {
    type: 'object',
    properties: {
      selected_sections: {
        type: 'array',
        items: {
          type: 'object',
          properties: {
            file: { type: 'string' },
            section_id: { type: 'string' },
            relevance: { type: 'string', enum: ['high', 'partial'] },
            reason: { type: 'string' }
          },
          required: ['file', 'section_id', 'relevance', 'reason']
        }
      },
      selected_pages: {
        type: 'array',
        items: {
          type: 'object',
          properties: {
            path: { type: 'string' },
            reason: { type: 'string' }
          },
          required: ['path', 'reason']
        }
      },
      excluded_pages: {
        type: 'array',
        items: {
          type: 'object',
          properties: {
            path: { type: 'string' },
            reason: { type: 'string' }
          },
          required: ['path', 'reason']
        }
      },
      excluded_sections: {
        type: 'array',
        items: {
          type: 'object',
          properties: {
            file: { type: 'string' },
            section_id: { type: 'string' },
            reason: { type: 'string' }
          },
          required: ['file', 'section_id', 'reason']
        }
      }
    },
    required: ['selected_sections', 'selected_pages', 'excluded_pages', 'excluded_sections']
  }}
)

log(`Semantic search complete. Found ${searchResult.selected_sections.length} sections.`)

// Step 4: Read section content
phase('ReadSections')

// Select up to 10 sections: high first, then partial
const highSections = searchResult.selected_sections.filter(s => s.relevance === 'high')
const partialSections = searchResult.selected_sections.filter(s => s.relevance === 'partial')
const sectionsToRead = [...highSections, ...partialSections].slice(0, 10)

const readSectionArgs = sectionsToRead.map(s => {
  // Extract just filename from path for the script
  const parts = s.file.split('/')
  const filename = parts[parts.length - 1]
  return `${filename}:${s.section_id}`
})

log(`Reading ${sectionsToRead.length} sections: ${readSectionArgs.join(', ')}`)

const sectionsContent = await agent(
  `Execute this bash command from directory /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6:

\`\`\`bash
cd /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6 && bash scripts/read-sections.sh ${readSectionArgs.map(a => `"${a}"`).join(' ')}
\`\`\`

Return the complete raw output of the command as a string.`,
  { label: 'read-sections', phase: 'ReadSections' }
)

log('Section content retrieved.')

// Step 5, 6, 7: Generate answer, verify, and finalize
phase('GenerateAnswer')

const ANSWER_SCHEMA = {
  type: 'object',
  properties: {
    answer_text: { type: 'string' },
    verify_result: { type: 'string', enum: ['PASS', 'FAIL'] },
    issues: { type: 'array', items: { type: 'string' } },
    final_answer: { type: 'string' },
    answer_sections_used: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          ref: { type: 'string' },
          reason: { type: 'string' }
        },
        required: ['ref', 'reason']
      }
    },
    answer_sections_unused: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          ref: { type: 'string' },
          reason: { type: 'string' }
        },
        required: ['ref', 'reason']
      }
    }
  },
  required: ['answer_text', 'verify_result', 'final_answer', 'answer_sections_used', 'answer_sections_unused']
}

const answerResult = await agent(
  `You are answering a Nablarch developer's question in Japanese.

## Question
フォームから受け取ったデータをDBに登録する処理の実装パターンを知りたい（処理方式: RESTfulウェブサービス）（目的: 実装したい）

## Processing type
RESTfulウェブサービス

## Purpose
実装したい

## Section content
${sectionsContent}

## Read section IDs
${readSectionArgs.join(', ')}

## Task

### Step 5: Generate answer

Generate a Japanese answer following this format (stay within 500 tokens, up to 800 for complex questions):

**結論**: Direct answer to the question (1–2 sentences)
- Include specific method names, class names, and approaches
- Do not parrot back the question

**根拠**: Code examples, configuration examples, or spec information that backs the conclusion
- Show code/config examples in code blocks
- Priority: implementation example > configuration example > API spec > conceptual explanation
- If using multiple sections, organize along the implementation flow
- Quote code examples from sections verbatim (do not modify)

**注意点**: Constraints, resource management, common mistakes
- Omit this section if nothing applies

参照: Only sections actually cited in the answer (file.json:sN format, omit category path)

### Step 6: Verify

Check that all Nablarch-specific claims in the answer are supported by the section content.

Extract claims in these categories:
- API names (method names, annotation names)
- Class names
- Configuration methods
- Behavior specs
- Constraints
- Parameters

Do NOT extract general Java/programming knowledge.

For each claim, judge:
1. Directly stated in section content → supported
2. Direct paraphrase → supported
3. Not explicitly stated → unsupported

If any claim is unsupported → verify_result = FAIL, record issues.
Otherwise → verify_result = PASS.

### Step 7: Handle result

If PASS: final_answer = answer_text
If FAIL: Re-generate answer without the unsupported claims. Save as final_answer.

### Output

Return JSON with:
- answer_text: the initial generated answer
- verify_result: PASS or FAIL
- issues: list of unsupported claims (empty array if PASS)
- final_answer: the verified final answer
- answer_sections_used: sections actually cited in the final answer with reasons
- answer_sections_unused: sections that were read but not used in the final answer with reasons`,
  { label: 'generate-answer', phase: 'GenerateAnswer', schema: ANSWER_SCHEMA }
)

log(`Answer generated. Verify result: ${answerResult.verify_result}`)

return {
  searchResult,
  sectionsToRead,
  readSectionArgs,
  answerResult
}
